const email = $('On Email Received').first().json;
const contact = $json; // From Supabase lookup

// Extract contact details (Ensure these match your Supabase columns)
const senderName = contact.full_name || email.from || 'Unknown';
const senderEmail = email.from || '';
const hospitalName = contact.hospital_name || '';
const departmentName = contact.department_name || '';
const role = contact.role || '';
const emailBody = email.body || email.bodyPreview || '';

// Build context with business rules
// TODO: Customize these rules for your business case
const businessRules = `
BUSINESS RULES:
- Replies must be short (max 2-3 short paragraphs, optional bullets), friendly, professional.
- No clinical or emergency medical advice; only equipment, pricing, logistics.
- Only suggest accessories relevant to the sender's department.
- Use consultative / solution-based selling, never hard sell.
- If unsure about technical detail or price, say you will confirm and follow up instead of guessing.
`;

const chatInput = `
Sender: ${senderName} (${senderEmail})
Hospital: ${hospitalName || 'Not available'}
Department: ${departmentName || 'Not available'}
Role: ${role || 'Not available'}

Email Subject: ${email.subject || 'No subject'}
Email Body:
${emailBody}

${businessRules}
`;

return {
  json: {
    chatInput: chatInput,
    originalEmail: email
  }
};
